args.sparql:
SELECT ?personLabel ?positionLabel WHERE {
  {
    wd:Q48340 wdt:P169 ?person .
    ?person rdfs:label ?personLabel .
    wd:P169 rdfs:label ?positionLabel .
    FILTER(LANG(?personLabel) = "en")
    FILTER(LANG(?positionLabel) = "en")
  }
  UNION {
    wd:Q48340 wdt:P488 ?person .
    ?person rdfs:label ?personLabel .
    wd:P488 rdfs:label ?positionLabel .
    FILTER(LANG(?personLabel) = "en")
    FILTER(LANG(?positionLabel) = "en")
  }
}

SELECT ?personLabel WHERE {
  wd:Q48340 wdt:P112 ?person .
  ?person rdfs:label ?personLabel .
  FILTER (LANG(?personLabel) = "en")
}
